create procedure [dbo].[CREATE_EXPA] @FromDate datetime, @ToDate datetime, @Tablename as varchar(50) output AS IF OBJECT_ID('dbo.EXPA','U') IS NOT NULL DROP TABLE EXPA CREATE TABLE EXPA ([Export Type] varchar(8) ,[Original Invoice Number] varchar(32) ,[Original Invoice date] varchar(21) , [Revised Invoice Number] varchar(32) , [Revised Invoice date] varchar(21) , [Total Invoice Value] decimal , [Ship Bill Code] varchar(32) , [Ship Bill Number] varchar(32) , [Ship Bill Date] varchar(21) , [Provisional Assessment] varchar(1) , [Category] varchar(1) , [HSN/SAC of Supply] varchar(16) , [Total Taxable Value] decimal , [IGST Rate] decimal , [IGST Amount] decimal , [CGST Rate] decimal ,[CGST Amount] decimal , [SGST Rate] decimal , [SGST Amount] decimal , [CESS Rate] decimal , [CESS Amount] decimal ,) Set @Tablename='EXPA' Select @Tablename 